import android.util.Log;

import java.io.IOException;
import okhttp3.Interceptor;
import okhttp3.Request;
import okhttp3.Response;
import okhttp3.ResponseBody;
import okio.Buffer;

public class NetworkLoggingInterceptor implements Interceptor {

    private static final String TAG = "NetworkLogger";

    @Override
    public Response intercept(Chain chain) throws IOException {
        Request request = chain.request();

        // Log request information
        logRequest(request);

        long startTime = System.nanoTime();
        Response response = chain.proceed(request);
        long endTime = System.nanoTime();

        // Log response information
        logResponse(response, (endTime - startTime) / 1e6f);

        return response;
    }

    private void logRequest(Request request) {
        try {
            String url = request.url().toString();
            String method = request.method();
            Headers headers = request.headers();

            Log.d(TAG, "Request URL: " + url);
            Log.d(TAG, "Request Method: " + method);

            for (String name : headers.names()) {
                if (!"Authorization".equalsIgnoreCase(name)) { // Avoid logging sensitive information
                    Log.d(TAG, "Header: " + name + ": " + headers.get(name));
                } else {
                    Log.d(TAG, "Header: Authorization: [REDACTED]");
                }
            }

            if ("POST".equalsIgnoreCase(method) || "PUT".equalsIgnoreCase(method)) {
                RequestBody requestBody = request.body();
                if (requestBody != null) {
                    Buffer buffer = new Buffer();
                    requestBody.writeTo(buffer);
                    String body = buffer.readUtf8();
                    Log.d(TAG, "Request Body: " + body);
                }
            }

        } catch (IOException e) {
            Log.e(TAG, "Error logging request", e);
        }
    }

    private void logResponse(Response response, float durationInMillis) {
        try {
            String url = response.request().url().toString();
            int code = response.code();
            Headers headers = response.headers();

            Log.d(TAG, "Response URL: " + url);
            Log.d(TAG, "Response Code: " + code);
            Log.d(TAG, "Response Time: " + durationInMillis + " ms");

            for (String name : headers.names()) {
                if (!"Authorization".equalsIgnoreCase(name)) { // Avoid logging sensitive information
                    Log.d(TAG, "Header: " + name + ": " + headers.get(name));
                } else {
                    Log.d(TAG, "Header: Authorization: [REDACTED]");
                }
            }

            ResponseBody responseBody = response.body();
            if (responseBody != null) {
                String body = responseBody.string();
                Log.d(TAG, "Response Body: " + body);
            }

        } catch (IOException e) {
            Log.e(TAG, "Error logging response", e);
        }
    }
}